local LCityBase = require("LApp.gameplay.city.base.LCityBase")

---@class LCityMonsterMgr:LCityBase 主界面怪物管理器
local LCityMonsterMgr = classX("LCityMonsterMgr", LCityBase)

function LCityMonsterMgr:ctor()
    LCityBase.ctor(self)
    self._npcTrans = nil
    ---@type table<number,LCityMonsterUnit>
    self._cityMonsters = {}
    ---@type table<number,LCityMonsterHud>
    self._cityMonsterHuds = {}
    self._hudCanvasRoot = nil
    self.combatPower = GameTable.CityMonsterConfigRef.combatPowerNum
    self.moveCamera = false
end
function LCityMonsterMgr:Initialize()
    LCityBase.Initialize(self)
    self:AddGpEvent(CityEvent.RefreshCityMonster, function()
        self:RefreshMonsters()
    end)
    self:AddGpEvent(CityEvent.RefreshCityMonsterHUD, function()
        self:RefreshHud()
    end)
    self:AddGpEvent(CityEvent.ShowCityMonster, function()
        self:ShowMonster()
    end)
    self:AddGpEvent(CityEvent.HideCityMonster, function()
        self:HideMonster()
    end)


end

function LCityMonsterMgr:Init(mapTrans)
    self._npcTrans = mapTrans:Find("ShakeRoot/NpcRoot")
    self._hudCanvasRoot = mapTrans:Find("HUDRoot")
    self:RefreshMonsters()
end
function LCityMonsterMgr:ShowMonster()
    for i, v in pairs(self._cityMonsters) do
        v:ShowMonster()
    end

    for i, v in pairs(self._cityMonsterHuds) do
        v:ShowHUD()
    end
end
function LCityMonsterMgr:HideMonster()
    for i, v in pairs(self._cityMonsters) do
        v:HideMonster()
    end
    for i, v in pairs(self._cityMonsterHuds) do
        v:HideHUD()
    end
end
function LCityMonsterMgr:RefreshMonsters()

    --do return end
    for i, v in pairs(self._cityMonsters) do
        local m = CtrlCenter.Role:GetMonsterById(i)
        if(m == nil)then
            local monster = self:GetMonsterUnit(i)
            if(monster)then
                monster:Dispose()
                self._cityMonsters[i] = nil
            end
        end
    end

    for i, v in pairs(self._cityMonsterHuds) do
        local m = CtrlCenter.Role:GetMonsterById(i)
        if(m == nil)then
            local hud = self:GetMonsterHud(i)
            if(hud)then
                hud:Dispose()
                self._cityMonsterHuds[i] = nil
            end
        end
    end
    local monsters = CtrlCenter.Role:GetCityMonsters()
    self._hudObj = FindChild(self._hudCanvasRoot,"MonsterHud")
    for i, v in pairs(monsters) do
        local monster = self:GetMonsterUnit(v)
        if(monster == nil)then
            monster = require("LApp.gameplay.city.view.LCityMonsterUnit"):new()
            self._cityMonsters[v] = monster
            monster:InitMonster(v,self,self.LoadMonsterCallBack,self)

        end

    end

    self:RefreshHud()
    if(ModuleCenter.Story:IsNewbieRunning())then
        self:HideMonster()
    else
        self:ShowMonster()
    end

end

function LCityMonsterMgr:LoadMonsterCallBack(refId)
    self:AddMonsterHUD(refId,self._cityMonsters[refId])
end

function LCityMonsterMgr:AddMonsterHUD(refId,monster)
    local hud = self:GetMonsterHud(refId)
    if(hud == nil)then
        hud = require("LApp.gameplay.city.view.LCityMonsterHud"):new()
        local obj = InstantObject(self._hudObj)
        obj.transform:SetParent(MgrCenter.UIMgr._hudCanvasTrans)
        PJXUtil.SetLayerMask(obj.transform,"UI")
        obj.transform.localScale = Vector3.one
        hud:SetHud(refId,monster._spineRoot.transform,obj,self)
        self._cityMonsterHuds[refId] = hud
        local danger = self:IsDanger(refId)
        hud:RefreshShowHud(danger)
    end
end
function LCityMonsterMgr:RefreshHud()
    for i, v in pairs(self._cityMonsterHuds) do
        local danger = self:IsDanger(i)
        v:RefreshShowHud(danger)
    end
end


function LCityMonsterMgr:IsDanger(refId)
    local cityMonsterRef = GameTable.CityMonsterRef[refId]
    if(cityMonsterRef == nil)then
        return false
    end
    local monsterRef = GameTable.MonsterFormationRef0[cityMonsterRef.monster]
    if(monsterRef == nil)then
        return false
    end
    local monsterPower = monsterRef.monsterPower
    local rolePower = ModuleCenter.Role:GetRolePower()
    local danger = monsterPower / rolePower >  self.combatPower
    return danger
end
function LCityMonsterMgr:GetMonsterUnit(refId)
    local monster = self._cityMonsters[refId]
    return monster
end
function LCityMonsterMgr:GetMonsterHud(refId)
    local hud = self._cityMonsterHuds[refId]
    return hud;
end
function LCityMonsterMgr:Dispose()
    self.moveCamera = false
    for i, v in pairs(self._cityMonsters) do
        v:Dispose()
    end
    for i, v in pairs(self._cityMonsterHuds) do
        v:Dispose()
    end
    table.dispose(self._cityMonsters)
    table.dispose(self._cityMonsterHuds)
    LCityBase.Dispose(self)
end
function LCityMonsterMgr:OnUpdate(deltaTime)
    for i, v in pairs(self._cityMonsterHuds) do
        v:OnUpdate(deltaTime)
    end
    for i, v in pairs(self._cityMonsters) do
        v:OnUpdate(deltaTime)
    end
end
return LCityMonsterMgr